#include <bits/stdc++.h>using namespace std;const int INF = 1e9 + 5;const int N = 3e5 + 5;int l[N], r[N];int pl[N], pr[N];int sl[N], sr[N];int main(){    int n;    cin >> n;    for (int i = 1; i <= n; i++)        cin >> l[i] >> r[i];    pl[0] = -INF;    pr[0] = INF;    for (int i = 1; i <= n; i++)    {        pl[i] = max(pl[i - 1], l[i]);        pr[i] = min(pr[i - 1], r[i]);    }    sl[n + 1] = -INF;    sr[n + 1] = INF;    for (int i = n; i >= 1; i--)    {        sl[i] = max(sl[i + 1], l[i]);        sr[i] = min(sr[i + 1], r[i]);    }    int ans = 0;    for (int i = 1; i <= n; i++)    {        int L = max(pl[i - 1], sl[i + 1]);        int R = min(pr[i - 1], sr[i + 1]);        ans = max(ans, R - L);    }    cout << ans;    return 0;}